const payload = $json.body ?? $json;

const pick = (...values) => values.find((value) => value !== undefined && value !== null && value !== '');

const dagId = pick(payload.dag_id, payload.dagId, payload.dag?.dag_id, 'desconocido');
const taskId = pick(payload.task_id, payload.taskId, payload.task?.task_id, 'desconocido');
const runId = pick(payload.run_id, payload.runId, payload.dag_run_id, 'desconocido');
const state = String(pick(payload.state, payload.status, 'desconocido')).toLowerCase();
const tryNumber = pick(payload.try_number, payload.tryNumber, payload.try, 'n/a');
const ts = pick(payload.ts, payload.timestamp, payload.execution_date, payload.logical_date, new Date().toISOString());
const logUrl = pick(payload.log_url, payload.logUrl, '');

const rawLog = pick(
  payload.log_excerpt,
  payload.log,
  payload.logs,
  payload.exception,
  payload.error,
  payload.message,
  ''
);

let logText = '';
if (typeof rawLog === 'string') {
  logText = rawLog;
} else if (rawLog) {
  logText = JSON.stringify(rawLog, null, 2);
}

const maxLogChars = 2800;
const truncatedLog = logText.length > maxLogChars
  ? `${logText.slice(0, maxLogChars)}\n\n[log truncado: ${logText.length - maxLogChars} caracteres omitidos]`
  : logText;

const header = [
  'AIRFLOW ETL ALERT',
  `state: ${state}`,
  `dag_id: ${dagId}`,
  `task_id: ${taskId}`,
  `run_id: ${runId}`,
  `try_number: ${tryNumber}`,
  `timestamp: ${ts}`,
];

if (logUrl) {
  header.push(`log_url: ${logUrl}`);
}

const text = [
  ...header,
  '',
  truncatedLog ? 'log_excerpt:' : 'sin log_excerpt en payload',
  truncatedLog || ''
].join('\n');

return [{
  json: {
    telegram_text: text,
    state,
    dag_id: dagId,
    task_id: taskId,
    run_id: runId
  }
}];
